choose.when:
SELECT * FROM ( SELECT p.PRODUCT_ID, p.PRODUCT_NAME, p.BRAND, c.CATEGORY_NAME, SUM(oi.QUANTITY) as TOTAL_SOLD, SUM(oi.QUANTITY * oi.UNIT_PRICE) as TOTAL_REVENUE, ROUND(AVG(oi.UNIT_PRICE), 2) as AVG_SELLING_PRICE, COUNT(DISTINCT o.USER_ID) as UNIQUE_BUYERS, RANK() OVER (ORDER BY SUM(oi.QUANTITY * oi.UNIT_PRICE) DESC) as REVENUE_RANK FROM PRODUCTS p, ORDER_ITEMS oi, ORDERS o, CATEGORIES c WHERE p.PRODUCT_ID = oi.PRODUCT_ID AND oi.ORDER_ID = o.ORDER_ID AND p.CATEGORY_ID = c.CATEGORY_ID(+) AND o.ORDER_STATUS NOT IN ('CANCELLED', 'REFUNDED') GROUP BY p.PRODUCT_ID, p.PRODUCT_NAME, p.BRAND, c.CATEGORY_NAME ORDER BY TOTAL_REVENUE DESC )
WHERE ROWNUM <= #{limit}
-- 전체 조회

mapper.select:
SELECT month_data.MONTH, month_data.CURRENT_REVENUE, month_data.PREVIOUS_REVENUE, CASE WHEN month_data.PREVIOUS_REVENUE > 0 THEN ROUND(((month_data.CURRENT_REVENUE - month_data.PREVIOUS_REVENUE) / month_data.PREVIOUS_REVENUE) * 100, 2) ELSE 0 END as GROWTH_RATE_PERCENTAGE, month_data.ORDER_COUNT, month_data.UNIQUE_CUSTOMERS FROM ( SELECT TO_CHAR(o.ORDERED_AT, 'YYYY-MM') as MONTH, SUM(o.TOTAL_AMOUNT) as CURRENT_REVENUE, LAG(SUM(o.TOTAL_AMOUNT)) OVER (ORDER BY TO_CHAR(o.ORDERED_AT, 'YYYY-MM')) as PREVIOUS_REVENUE, COUNT(*) as ORDER_COUNT, COUNT(DISTINCT o.USER_ID) as UNIQUE_CUSTOMERS FROM ORDERS o WHERE o.ORDER_STATUS NOT IN ('CANCELLED', 'REFUNDED')
AND EXTRACT(YEAR FROM o.ORDERED_AT) = #{year}
GROUP BY TO_CHAR(o.ORDERED_AT, 'YYYY-MM') ) month_data ORDER BY month_data.MONTH
